export default GenerateI864;


const beneficiariesNotMain = (obj) => {
	let ddd = [];
	obj?.beneficiariesInfo && ObjectKeys(obj?.beneficiariesInfo).map(v=>{
		if(obj?.main_beneficiarie !== v){
			ddd.push(v);
		}
	});
	return ddd;
};


 
const BenefisiariesItem  = ({ item, keyId, rmv, updMainB, updObs }) => {

	const [obs, set_obs] = useState(1);


	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};


	const updRelationBeneficiary =  (v) => {
		let relationMain = getStore(frmNm)?.relationMain || {};
		if(Array.isArray(relationMain)){
			relationMain ={};
		}
		if(v){
			relationMain[keyId] = v;
		}else{
			delete relationMain[keyId] 
		}
		updFrm("relationMain",relationMain);
		updObs();
	}

	return (
		<div className=" benef_bx _dsplFlx ">
			
			<div className="auto_align">
				{item?.firstName}
			</div>
			<div className="flexSpace"/>
			<div className="_dsplFlx auto_align " >
				<CheckBoxSlide
					initvalue={getStore(frmNm)?.["main_beneficiarie"]===keyId}
					keyCode={37}
					updChange={(e)=>updMainB(e,keyId)}
					color={"var(--primary)"}
				/>
				<span className={`checklabel`}>
					{"is Main Beneficiarie"}
				</span>
			</div>
			<div className="flexSpace"/>
			<div style={{marginTop:1}}>
				<DropDwnPicker 
					init={getStore(frmNm)?.["relationMain"]?.[keyId]}
					lbl_empty={"Relation with Main"} 
					list={
						[
							{label: "Son", id:"Son"},
							{label: "Daughter", id:"Daughter"},
							{label: "Husband", id:"Husband"},
							{label: "Wife", id:"Wife"},
							{label: "None", id:null},
						]
					}
					onSelect={(e)=>updRelationBeneficiary(e.id)} 
					background={"var(--dark-700)"}
					color={"var(--light-200)"}
				/>
			</div>
			<div className="flexSpace"/>
			<div  className="icon_action auto_align"	onClick={()=>rmv(keyId)}>
				<Svg name={"outline_delete"}	/>
			</div>
		</div>
	)

}



 
const RegisterAgentDropD  = ({ init, emptyLabel, onSelect }) => {

	const [list, setList] = useState([]);

	const parseD =  (v) => {
		let nA = []
		v && ObjectKeys(v).map(cl=>{
			let fullNm = txtOrempty(v[cl]?.name);
			nA.push({id:cl, label: fullNm });
		});
		setList(sortByName(nA,"name"));
	}

	const fetch =  (v) => {
		search_notaryAgent(v, parseD);

	}

	const clear =  () => {
		setList([]);
	}



	return (
		<div style={{minWidth: 260}}>
			<DropDwnSearchPicker
				lbl_empty={init || emptyLabel} 
				list={list}
				onSelect={(e)=>onSelect(e)} 
				background={"var(--dark-900)"}
				color={"var(--primary)"}
				callempty={clear}
				fetchData={fetch}
			/>
		</div>
	)

}





